-- Resistance field guide as a TipTap note (published + template = unlisted on /notes, direct link only).
-- Edit body in Admin like any other note. Public URL: /notes/working-with-resistance

insert into public.notes (slug, title, excerpt, content_json, published, published_at, is_template)
values (
  'working-with-resistance',
  $TITLE$What to do when there's tension$TITLE$,
  $EXCERPT$Facilitator field notes — On working with resistance$EXCERPT$,
  $DOCJSON${"type":"doc","content":[{"type":"thusnessHero","content":[{"type":"paragraph","content":[{"type":"text","text":"Facilitator field notes · On working with resistance"}]},{"type":"paragraph","content":[{"type":"text","text":"~ A field guide","marks":[{"type":"italic"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"What to do when there's tension."}]},{"type":"paragraph","content":[{"type":"text","text":"for the person sitting beside it","marks":[{"type":"italic"}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ The premise"}]}]},{"type":"paragraph","content":[{"type":"text","text":"You aren't trying to "},{"type":"text","text":"remove","marks":[{"type":"italic"}]},{"type":"text","text":" tension, "},{"type":"text","text":"fix","marks":[{"type":"italic"}]},{"type":"text","text":" it, or "},{"type":"text","text":"analyze","marks":[{"type":"italic"}]},{"type":"text","text":" it. You're getting curious about it, and that quietly changes the relationship."}]},{"type":"paragraph","content":[{"type":"text","text":"Resistance is a quiet "},{"type":"text","text":"no","marks":[{"type":"italic"}]},{"type":"text","text":" to what's already here. Don't fight the no. "},{"type":"text","text":"Include","marks":[{"type":"italic"}]},{"type":"text","text":" it, or "},{"type":"text","text":"widen","marks":[{"type":"italic"}]},{"type":"text","text":" around it."}]},{"type":"thusnessPullQuote","content":[{"type":"paragraph","content":[{"type":"text","text":"Never fight resistance.\nAlways include or expand."}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Core mini-script"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Okay… just gently notice that tension… with a bit of curiosity… where is it, if anywhere… is it in one place, or changing… what's the quality of it… tight… heavy… moving… still… does it need to be different right now… or could it be included, just as part of the experience… and if you're with it… just seeing what happens on its own…","marks":[{"type":"italic"}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Five moves"}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"01 · Include it"}]},{"type":"paragraph","content":[{"type":"text","text":"When ","marks":[{"type":"bold"}]},{"type":"text","text":"Contraction, discomfort, this feels bad. The default move."}]},{"type":"paragraph","content":[{"type":"text","text":"Script ","marks":[{"type":"bold"}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Just noticing that resistance… with a bit of gentle curiosity… where do you feel it… is it okay for it to be here, just for now… can it be part of the experience…","marks":[{"type":"italic"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Why ","marks":[{"type":"bold"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Resistance is pushing away. You quietly remove the push."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"02 · Widen around it"}]},{"type":"paragraph","content":[{"type":"text","text":"When ","marks":[{"type":"bold"}]},{"type":"text","text":"Stuck inside it. Overwhelmed. Narrowed to one point."}]},{"type":"paragraph","content":[{"type":"text","text":"Script ","marks":[{"type":"bold"}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Just notice the tension… gently… now also notice sounds in the room… sensations elsewhere in the body… letting everything be included… being a little curious about the whole field…","marks":[{"type":"italic"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Why ","marks":[{"type":"bold"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Breaks narrow fixation. The tension stops being the whole world."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"03 · Appreciation softener"}]},{"type":"paragraph","content":[{"type":"text","text":"When ","marks":[{"type":"bold"}]},{"type":"text","text":"Sticky resistance, subtle frustration, mental looping."}]},{"type":"paragraph","content":[{"type":"text","text":"Script ","marks":[{"type":"bold"}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Is there anything about this you don't mind… or even slightly appreciate… just gently curious… even just noticing that it's here…","marks":[{"type":"italic"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Why ","marks":[{"type":"bold"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Replaces force with openness. The grip loosens on its own."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"04 · Turning"}]},{"type":"paragraph","content":[{"type":"text","text":"When ","marks":[{"type":"bold"}]},{"type":"text","text":"Strong contraction, repetitive pattern, deeper inquiry possible. Advanced. Only when stable."}]},{"type":"paragraph","content":[{"type":"text","text":"Script ","marks":[{"type":"bold"}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Just notice the tension… gently… and just see, with a bit of curiosity… what's noticing it… can both be noticed together…","marks":[{"type":"italic"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Why ","marks":[{"type":"bold"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Collapses the subject / object split. The one resisting and the resistance arrive together."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"05 · Hold it next to peace"}]},{"type":"paragraph","content":[{"type":"text","text":"When ","marks":[{"type":"bold"}]},{"type":"text","text":"Once things have softened. Let resistance stay where it is, and notice the quiet that's already in the room."}]},{"type":"paragraph","content":[{"type":"text","text":"Script ","marks":[{"type":"bold"}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Just notice the resistance… and, gently, also notice the peace that's already here… letting one be held next to the other… and seeing what happens on its own…","marks":[{"type":"italic"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Why ","marks":[{"type":"bold"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Don't pick one. Don't replace one with the other. Often, one quietly invites the other in."}]},{"type":"paragraph","content":[{"type":"text","text":""}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Clean rules"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Avoid Don't say \"relax it,\" \"let it go,\" or \"release it.\" They're all instructions to push. They create more resistance."}]}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Always Include, or widen. With *gentle curiosity*. Never force."}]}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Fallback If you blank out: *\"Just notice it… with a bit of gentle curiosity… and let it be part of what's here…\"*"}]}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Decision tree"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Are they overwhelmed? "},{"type":"text","text":"→ ","marks":[{"type":"bold"}]},{"type":"text","text":"Widen "},{"type":"text","text":"(Strategy 2)","marks":[{"type":"italic"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Are they resisting it? "},{"type":"text","text":"→ ","marks":[{"type":"bold"}]},{"type":"text","text":"Include "},{"type":"text","text":"(Strategy 1)","marks":[{"type":"italic"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Are they stuck or looping? "},{"type":"text","text":"→ ","marks":[{"type":"bold"}]},{"type":"text","text":"Appreciation "},{"type":"text","text":"(Strategy 3)","marks":[{"type":"italic"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Are they stable enough? "},{"type":"text","text":"→ ","marks":[{"type":"bold"}]},{"type":"text","text":"Turning "},{"type":"text","text":"(Bonus)","marks":[{"type":"italic"}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Holding both"}]}]},{"type":"paragraph","content":[{"type":"text","text":"~ Here ","marks":[{"type":"bold"}]},{"type":"text","text":"resistance","marks":[{"type":"italic"}]},{"type":"text","text":" · "},{"type":"text","text":"tight, narrow, pushing away","marks":[{"type":"italic"}]}]},{"type":"paragraph","content":[{"type":"text","text":"~ Also here ","marks":[{"type":"bold"}]},{"type":"text","text":"peace","marks":[{"type":"italic"}]},{"type":"text","text":" · "},{"type":"text","text":"open, quiet, already present","marks":[{"type":"italic"}]}]},{"type":"thusnessPullQuote","content":[{"type":"paragraph","content":[{"type":"text","text":"Don't pick one. Don't replace one with the other. Hold them side by side, and see what happens on its own."}]}]}]}$DOCJSON$::jsonb,
  true,
  now(),
  true
)
on conflict (slug) do update set
  title = excluded.title,
  excerpt = excluded.excerpt,
  content_json = excluded.content_json,
  published = excluded.published,
  is_template = excluded.is_template,
  updated_at = now();
